class SecureKeyManager:
    """
    Manages encryption keys securely. In production, this should integrate
    with a proper key management service (AWS KMS, Azure Key Vault, 
    HashiCorp Vault, etc.).
    """

    def __init__(self, key_storage_path=None):
        self._key_storage_path = key_storage_path or os.environ.get(
            "ENCRYPTION_KEY_PATH"
        )
        self._cached_key = None

    def get_encryption_key(self) -> bytes:
        """
        Retrieve the encryption key from secure storage.
        In production, replace this with calls to your KMS/Vault.
        """
        # First, try environment variable (set via secure secret injection)
        env_key = os.environ.get("DATA_ENCRYPTION_KEY")
        if env_key:
            return base64.urlsafe_b64decode(env_key)

        # Then, try reading from a secure file (e.g., mounted secret volume)
        if self._key_storage_path and os.path.exists(self._key_storage_path):
            with open(self._key_storage_path, "rb") as f:
                return f.read()

        raise EnvironmentError(
            "Encryption key not found. Set DATA_ENCRYPTION_KEY environment variable "
            "or configure ENCRYPTION_KEY_PATH to point to a secure key file. "
            "Never hardcode keys in source code."
        )

    @staticmethod
    def generate_new_key() -> bytes:
        """Generate a new 256-bit encryption key using cryptographically secure randomness."""
        return secrets.token_bytes(32)

    @staticmethod
    def derive_key_from_password(password: str, salt: bytes = None) -> tuple:
        """Derive an encryption key from a password using PBKDF2."""
        if salt is None:
            salt = secrets.token_bytes(16)

        kdf = PBKDF2HMAC(
            algorithm=hashes.SHA256(),
            length=32,
            salt=salt,
            iterations=600_000,  # OWASP recommended minimum
        )
        key = kdf.derive(password.encode("utf-8"))
        return key, salt


