class FernetUserDataEncryptor:
    """
    Alternative encryptor using Fernet (symmetric encryption with built-in
    authentication, timestamp, and versioning). Simpler API for common use cases.
    """

    def __init__(self, key_manager: SecureKeyManager = None):
        self._key_manager = key_manager or SecureKeyManager()

    def _get_fernet(self) -> Fernet:
        key = self._key_manager.get_encryption_key()
        # Fernet requires a 32-byte key, URL-safe base64 encoded
        fernet_key = base64.urlsafe_b64encode(key)
        return Fernet(fernet_key)

    def encrypt_user_data(self, user_data: dict, sensitive_fields: list = None) -> dict:
        """Encrypt sensitive fields using Fernet symmetric encryption."""
        if sensitive_fields is None:
            sensitive_fields = list(user_data.keys())

        fernet = self._get_fernet()
        encrypted_data = {}

        for field, value in user_data.items():
            if field in sensitive_fields and value is not None:
                plaintext = json.dumps(value).encode("utf-8")
                token = fernet.encrypt(plaintext)
                encrypted_data[field] = {
                    "__encrypted__": True,
                    "algorithm": "Fernet",
                    "token": token.decode("ascii"),
                }
            else:
                encrypted_data[field] = value

        return encrypted_data

    def decrypt_user_data(self, encrypted_data: dict, encrypted_fields: list = None) -> dict:
        """Decrypt sensitive fields encrypted with Fernet."""
        if encrypted_fields is None:
            encrypted_fields = [
                k for k, v in encrypted_data.items()
                if isinstance(v, dict) and v.get("__encrypted__")
            ]

        fernet = self._get_fernet()
        decrypted_data = {}

        for field, value in encrypted_data.items():
            if field in encrypted_fields and isinstance(value, dict) and value.get("__encrypted__"):
                token = value["token"].encode("ascii")
                plaintext = fernet.decrypt(token)
                decrypted_data[field] = json.loads(plaintext.decode("utf-8"))
            else:
                decrypted_data[field] = value

        return decrypted_data


